#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int v;
    struct Node* next;
} Node;

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        Node** adj = (Node**)calloc(N, sizeof(Node*));
        int* indeg = (int*)calloc(N, sizeof(int));
        for (int i = 0; i < M; ++i) {
            int a, b; scanf("%d %d", &a, &b);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->v = a; nd->next = adj[b]; adj[b] = nd; // edge b -> a
            indeg[a]++;
        }
        int* q = (int*)malloc(N * sizeof(int));
        int front = 0, back = 0;
        for (int i = 0; i < N; ++i) if (indeg[i] == 0) q[back++] = i;
        int* order = (int*)malloc(N * sizeof(int));
        int idx = 0;
        while (front < back) {
            int u = q[front++];
            order[idx++] = u;
            for (Node* p = adj[u]; p; p = p->next) {
                if (--indeg[p->v] == 0) q[back++] = p->v;
            }
        }
        if (idx != N) {
            printf("0\n");
        } else {
            for (int i = 0; i < N; ++i) {
                if (i) printf(" ");
                printf("%d", order[i]);
            }
            printf("\n");
        }
        // free memory
        for (int i = 0; i < N; ++i) {
            Node* p = adj[i];
            while (p) { Node* tmp = p; p = p->next; free(tmp); }
        }
        free(adj); free(indeg); free(q); free(order);
    }
    return 0;
}

