    while (T--) {
        int N, M; cin >> N >> M;
        vector<vector<int>> adj(N);
        vector<int> indeg(N, 0);
        for (int i = 0; i < M; ++i) {
            int a, b; cin >> a >> b;
            adj[b].push_back(a); // b -> a
            indeg[a]++;
        }
        queue<int> q;
        for (int i = 0; i < N; ++i) if (indeg[i] == 0) q.push(i);
        vector<int> order;
        while (!q.empty()) {
            int u = q.front(); q.pop();
            order.push_back(u);
            for (int v : adj[u]) {
                if (--indeg[v] == 0) q.push(v);
            }
        }
        if ((int)order.size() != N) {
            cout << 0 << '\n';
        } else {
            for (int i = 0; i < N; ++i) {
                if (i) cout << ' ';
                cout << order[i];
            }
            cout << '\n';
        }
    }
    return 0;
}

