#!/usr/bin/env python3
import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        adj = [[] for _ in range(N)]
        indeg = [0] * N
        for _ in range(M):
            a = int(next(it))
            b = int(next(it))
            adj[b].append(a)  # b -> a
            indeg[a] += 1
        q = deque([i for i in range(N) if indeg[i] == 0])
        order = []
        while q:
            u = q.popleft()
            order.append(u)
            for v in adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        if len(order) != N:
            out_lines.append('0')
        else:
            out_lines.append(' '.join(map(str, order)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

